import { REQUEST_USER, LOAD_USER, SUCESS_USER, LOGOUT_USER } from "../constants/userConstants";
import axios from "axios";

export const loginUser = (userData) => async (dispatch) => {
    try {
        const config = { headers: { "Content-Type": "application/x-www-form-urlencoded" } };
        const { data } = await axios.post("https://api-dev.billfy.in/factory_operator_login", userData, config);
        localStorage.setItem("accessToken", data.accessToken);
        dispatch({ type: SUCESS_USER, payload: data.user });
    } catch (error) {
        console.log(error);
    }
}

export const loadUser = () => async (dispatch) => {
    try {
        const token = localStorage.getItem("accessToken");
        if (token) {
            const config = { headers: { "Content-Type": "application/x-www-form-urlencoded" } };
            const { data } = await axios.post("https://api-dev.billfy.in/load_factory_operator", { token: token }, config);
            dispatch({ type: LOAD_USER, payload: data.user });
        }
    } catch (error) {
        console.log(error);
    }
}

export const logoutUser = () => async (dispatch) => {
    try {
        const token = localStorage.getItem("accessToken");
        const config = { headers: { "Content-Type": "application/x-www-form-urlencoded" } };
        const { data } = await axios.post("https://api-dev.billfy.in/factory_operator_logout", { token: token }, config);
        console.log(data);
        localStorage.removeItem("accessToken");
        dispatch({ type: LOGOUT_USER });
    } catch (error) {
        console.log(error);
    }
}

