import { SUCCESS_QR } from "../constants/qrConstants";
import axios from "axios";

export const getQrUrl = (qrData) => async (dispatch) => {
    try {
        console.log(qrData);
        const config = { headers: { "Content-Type": "application/x-www-form-urlencoded" } };
        const { data } = await axios.post("https://api-dev.billfy.in/print_QR", qrData, config);
        console.log(data);
        dispatch({ type: SUCCESS_QR, payload: data });
    } catch (error) {
        console.log(error);
    }
}