import React, { useEffect, useState } from 'react'
import './home.scss'
import ClearIcon from '@mui/icons-material/Clear';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';
import ArrowDropDownIcon from '@mui/icons-material/ArrowDropDown';
import { Button } from '@mui/material';
import { useNavigate } from 'react-router-dom';

import anim1 from '../../assests/anim1.gif'
import anim2 from '../../assests/anim2.gif'
import Product from '../../components/product/Product';
import { useDispatch, useSelector } from 'react-redux';
import { logoutUser } from '../../action/userActions';
import { getProducts } from '../../action/productAction';
import { getQrUrl } from '../../action/qrActions';

import { saveAs } from 'file-saver'


const Home = () => {

    const navigate = useNavigate();




    ///////////////////////////////////////////////////////// qrData ///////////////////////////////////
    const [qrData, setQrData] = useState({
        product_id: "",
        factory_operator_id: "",
        quantity: 1,
        serial_no: ""
    });

    const handleChange = (e) => {
        setQrData({ ...qrData, [e.target.name]: e.target.value });
    }





    ///////////////////////////////////////////// states /////////////////////////////////////////////////
    // const [state1, setState1] = useState(true);
    // const [state2, setState2] = useState(false);
    // const [state3, setState3] = useState(false);



    /////////////////////////////////////////////////// quantity /////////////////////////////////////

    const [quantity, setQuantity] = useState(1);

    const dec = () => {
        if (quantity > 1) {
            setQuantity(Number(quantity) - 1);
            setQrData({ ...qrData, "quantity": Number(quantity) - 1 });
        }
    }
    const inc = () => {
        if (!quantity) {
            setQuantity(1);
            setQrData({ ...qrData, "quantity": 1 });

        } else {
            setQuantity(Number(quantity) + 1);
            setQrData({ ...qrData, "quantity": Number(quantity) + 1 });
        }
    }

    const handleQuantity = (e) => {
        const result = e.target.value.replace(/\D/g, '');
        setQuantity(Number(result));
        setQrData({ ...qrData, "quantity": Number(result) });
    }



    ///////////////////////////////////////////////////////// product ////////////////////////////////////////

    const [showProduct, setProduct] = useState(false);
    const [productName, setProductName] = useState("");

    const [productArray, setProductArray] = useState([
        {
            product_name: "",
            product_model: "",
            images: [{ image: "" }]
        }
    ]);

    const closeAll = () => {
        setProduct(false);
    }

    const fun = (data) => {
        setProductName(data.product_name);
        setQrData({ ...qrData, "product_id": data.id })
        closeAll();
    }



    /////////////////////////////// authentication ///////////////////////////////
    const dispatch = useDispatch();
    const token = localStorage.getItem("accessToken");
    const { user } = useSelector(state => state.userReducer);
    const { products } = useSelector(state => state.productReducer);

    useEffect(() => {
        if (!token && !user) {
            navigate('/login');
        }
    }, [user, token, navigate]);


    ////////////////////////////////////// redux ///////////////////////////////////////
    const logout = () => {
        dispatch(logoutUser());
    }


    useEffect(() => {
        if (user) {
            dispatch(getProducts(user.factory_id));
            setQrData({ ...qrData, "factory_operator_id": user.id });
        }
    }, [user, dispatch]);

    useEffect(() => {
        if (products) {
            setProductArray(products);
        }
    }, [products]);



    const generateQr = () => {
        // setState1(false);
        // setState2(true);

        // setTimeout(() => {
        //     setState2(false);
        //     setState3(true);
        // }, 8000);
        dispatch(getQrUrl(qrData));
    }



    const { qrUrl } = useSelector(state => state.qrReducer);
    // const [url, setUrl] = useState("");

    useEffect(() => {
        if (qrUrl) {
            console.log(qrUrl);
            // setUrl(qrUrl);
            saveAs(qrUrl, "qrPdf");
            setQrData({
                product_id: "",
                factory_operator_id: user.id,
                quantity: 1,
                serial_no: ""
            });
            setProductName("");
        }
    }, [qrUrl]);


    // const download = () => {
    // }


    return (
        <>
            <div className='main'>
                <div className='home' onClick={closeAll}>
                    <div id='inner'>

                        <div id="line"></div>

                        <div className='innerScroll'>

                            <div>

                                <button className='btn but1' onClick={logout}><ClearIcon /></button>

                                <div className='head'>
                                    <div>Print QR code</div>
                                    <section>
                                        Select a product and enter number of QR code
                                        you want to print and click download
                                    </section>
                                </div>


                                <form>


                                    <div className="form-group select">
                                        <label>Product</label>
                                        <input type="text" className="form-control" readOnly style={{ cursor: "pointer" }} value={productName} placeholder="Select Product" onClick={(e) => { e.stopPropagation(); setProduct(!showProduct) }} />
                                        <ArrowDropDownIcon className='icon' />

                                        {showProduct ? <div className='selectProduct' onClick={(e) => e.stopPropagation()}>

                                            {productArray.map((val, index) => {
                                                return (
                                                    <Product key={index} data={val} fun={fun} />
                                                );
                                            })}

                                        </div> : null}

                                    </div>



                                    <div className="form-group select">
                                        <label>Starting Serial Number</label>
                                        <input type="text" className="form-control" name="serial_no" value={qrData.serial_no} placeholder='Enter first serial Number of product' onChange={handleChange} />
                                    </div>


                                    <div className="form-group">
                                        <label>Quantity</label>
                                        <div className='grid1'>
                                            <div className='d1'> <input type="text" className="form-control" aria-describedby="emailHelp" placeholder="Quantity" value={quantity} onChange={handleQuantity} />  </div>
                                            <div className='d2'> <Button variant='contained' className='bt3' onClick={dec}><RemoveIcon fontSize='medium' /></Button> </div>
                                            <div className='d2'> <Button variant='contained' className='bt3' onClick={inc}><AddIcon fontSize='medium' /></Button> </div>
                                        </div>
                                    </div>


                                </form>

                                <div className='genBox'> <Button className='generate' variant='contained' onClick={generateQr}>Generate QR</Button> </div>

                            </div>

                            {/* {state2 ? <div className='animation1'>
                                <img src={anim1} alt="" />
                                <div>Hold on! QR File is Generating</div>
                            </div> : null}

                            {state3 ? <div className='animation1'>
                                <img src={anim2} alt="" />
                                <div>QR File is ready to Download</div>
                            </div> : null}

                            {state3 ? <div className='download' onClick={download}> <Button className='bt' variant='contained'>Download File</Button> </div> : null} */}


                        </div>
                    </div>
                </div>
            </div>
        </>
    )
}

export default Home